9	/**
10	 * In-memory colour scheme manager for tests to avoid touching runtime
11	 * localStorage and triggering Node experimental warnings.
12	 */
13	const testColorSchemeManager = {
14	    get: (defaultValue: 'auto' | 'dark' | 'light') => defaultValue,
15	    set: () => undefined,
16	    subscribe: () => undefined,
17	    unsubscribe: () => undefined,
18	    clear: () => undefined,
19	};
20	
21	/**
22	 * Test wrapper component that provides Mantine theming context.
23	 * Wraps children with MantineProvider configured for light color scheme.
24	 *
25	 * @param props - The component props
26	 * @param props.children - React nodes to be wrapped with Mantine provider
27	 * @returns A React component with Mantine provider context
28	 */
29	export const Wrapper = ({ children }: WrapperProps) => {
30	    return (
31	        <MantineProvider colorSchemeManager={testColorSchemeManager} defaultColorScheme="light">
32	            {children}
33	        </MantineProvider>
34	    );
35	};
36	
37	/**
38	 * Extracts and parses props from a rendered element's text content. Each
39	 * standard mock is expected to render a single element whose text looks like:
40	 * `<div>{id}: {JSON.stringify(props)}</div>`, for example:
41	 * `<div>MyComponent: {"prop1":"value1"}</div>`.
42	 *
43	 * This deliberately uses loose JSON parsing rather than zod schema validation
44	 * to keep tests simple and focused on rendering behavior.
45	 *
46	 * @template T - The type of the props object to be returned.
47	 * @param id - The identifier prefix used to locate the element. The function
48	 * looks for text starting with `${id}:` and parses the JSON that follows.
49	 * @returns The parsed props object(s) of type T.
50	 * @throws Will fail test assertions if the element is not found or if the JSON
51	 * is invalid.
52	 *
53	 * @example
54	 * // For `<div>MyComponent: {"prop1":"value1"}</div>`:
55	 * const [props] = extractMockProps<MyComponentProps>('MyComponent');
56	 */
57	export const extractMockProps = <T,>(id: string) => {
58	    const mockElements = screen.getAllByText(new RegExp(`^${id}:`));
59	    const result: T[] = [];
60	    for (const element of mockElements) {
61	        const json = element.textContent?.replace(new RegExp(`^${id}:\\s*`), '');
62	        expect(typeof json).toBe('string');
63	        expect(json.trim()).not.toBe('');
64	        result.push(JSON.parse(json) as T);
65	    }
66	    expect(result.length).toBeGreaterThan(0);
67	    return result;
68	};
