21	        await asAdmin(page, '/footy/admin/responses');
22	
23	        await expect(page.getByRole('heading', { name: /Responses/i })).toBeVisible();
24	
25	        // Read a group's player count from its h2 heading ("Yes: 15").
26	        // CSS + text filter works regardless of whether the card has an explicit ARIA role.
27	        const groupCount = async (title: string) => {
28	            const heading = page.locator('h2').filter({ hasText: new RegExp(`^${title}:\\s*`) });
29	            if (await heading.count() === 0) return 0;
30	            const text = await heading.first().innerText();
31	            const match = /:\s*(\d+)$/.exec(text.trim());
32	            return match ? Number(match[1]) : 0;
33	        };
34	
35	        const initialYes = await groupCount('Yes');
36	        const initialNo = await groupCount('No');
37	        const initialDunno = await groupCount('Dunno');
38	        const initialNone = await groupCount('None');
39	
40	        const startsFromNone = initialNone > 0;
41	        const yesAfterFirstUpdate = startsFromNone ? initialYes + 1 : initialYes;
42	        const noneAfterFirstUpdate = startsFromNone ? initialNone - 1 : initialNone;
43	
44	        // Yes group renders before None; skip past Yes rows to reach the first None player.
45	        const targetRow = page.locator('[data-player-id]').nth(startsFromNone ? initialYes : 0);
46	        const playerId = await targetRow.getAttribute('data-player-id');
47	
48	        if (!playerId) {
49	            throw new Error('Expected player row to have a data-player-id attribute.');
50	        }
51	
52	        // Tracks the player by ID across group changes — they appear in exactly one group at a time.
53	        const playerRow = page.locator(`[data-player-id="${playerId}"]`);
54	
55	        const setResponseValue = async (response: ResponseOption) => {
