94	
95	        await expect.poll(async () => groupCount('Yes'), { timeout: 10000 }).toBe(yesAfterFirstUpdate - 1);
96	        await expect.poll(async () => groupCount('No'), { timeout: 10000 }).toBe(initialNo);
97	        await expect.poll(async () => groupCount('Dunno'), { timeout: 10000 }).toBe(initialDunno + 1);
