1	'use client';
2	
3	import type { MantineColor } from '@mantine/core';
4	import {
5	    Button,
6	    Card,
7	    CardSection,
8	    Checkbox,
9	    Flex,
10	    Group,
11	    Select,
12	    Stack,
13	    Text,
14	    TextInput,
15	    Title,
16	} from '@mantine/core';
17	import { useForm } from '@mantine/form';
18	import { notifications } from '@mantine/notifications';
19	import { IconAlertTriangle, IconCheck } from '@tabler/icons-react';
20	import { PlayerResponse } from 'prisma/generated/enums';
21	import { useEffect, useMemo, useRef, useState } from 'react';
22	
23	import { config } from '@/lib/config';
24	import { SubmitResponseProxy } from '@/types/actions/SubmitResponse';
25	import { OutcomePlayerType } from '@/types/OutcomePlayerType';
26	
27	interface ResponsesFormProps {
28	    gameId: number;
29	    gameDate: string;
30	    responses: OutcomePlayerType[];
31	    submitResponse: SubmitResponseProxy;
32	}
33	
34	type ResponseOption = PlayerResponse | 'None';
35	const ResponseOption = {
36	    ...PlayerResponse,
37	    None: 'None' as const,
38	};
39	
40	type ResponseValues = Pick<OutcomePlayerType, 'response' | 'goalie' | 'comment'>;
41	interface ResponsesFormValues {
42	    byPlayerId: Record<number, ResponseValues>;
43	}
44	
45	const toResponseValues = (row: OutcomePlayerType): ResponseValues => ({
46	    response: row.response ?? null,
47	    goalie: !!row.goalie,
48	    // v8 ignore next -- comment is always a string in practice (Prisma default '')
49	    comment: row.comment ?? '',
50	});
51	
52	const responseGroupBarColor: Record<ResponseOption, MantineColor> = {
53	    [ResponseOption.Yes]: 'green.6',
54	    [ResponseOption.No]: 'red.6',
55	    [ResponseOption.Dunno]: 'yellow.6',
56	    [ResponseOption.Excused]: 'gray.6',
57	    [ResponseOption.Flaked]: 'gray.6',
58	    [ResponseOption.Injured]: 'gray.6',
59	    [ResponseOption.None]: 'gray.6',
60	};
61	
62	export const ResponsesForm = ({
63	    gameId,
64	    gameDate,
65	    responses,
66	    submitResponse,
67	}: ResponsesFormProps) => {
68	    const form = useForm<ResponsesFormValues>({
69	        initialValues: {
70	            byPlayerId: Object.fromEntries(responses.map((row) => [row.playerId, toResponseValues(row)])),
71	        },
72	    });
73	    const [savingId, setSavingId] = useState<number | null>(null);
74	    const [filter, setFilter] = useState('');
75	
76	    // Re-sync form values when the responses prop changes (e.g. after
77	    // revalidate / SSE refresh). Preserve any in-progress edits by only
78	    // overwriting rows whose form values still match the previous baseline.
79	    const prevResponsesRef = useRef(responses);
80	    useEffect(() => {
81	        const prevBaselineById = new Map(
82	            prevResponsesRef.current.map((row) => [row.playerId, toResponseValues(row)]),
83	        );
84	        for (const row of responses) {
85	            const newBaseline = toResponseValues(row);
86	            const oldBaseline = prevBaselineById.get(row.playerId) ?? newBaseline;
87	            const current = form.values.byPlayerId[row.playerId];
88	            const userEdited =
89	                !!current && (
90	                    current.response !== oldBaseline.response ||
91	                    current.goalie !== oldBaseline.goalie ||
92	                    current.comment !== oldBaseline.comment
93	                );
94	            if (!userEdited) {
95	                form.setFieldValue(`byPlayerId.${row.playerId}`, newBaseline);
96	            }
97	        }
98	        prevResponsesRef.current = responses;
99	        // eslint-disable-next-line react-hooks/exhaustive-deps -- form identity is stable; we only want to react to responses changes
100	    }, [responses]);
101	
102	    const isRowDirty = (row: OutcomePlayerType) => {
103	        const baseline = toResponseValues(row);
104	        // v8 ignore next -- form is always initialised from the same rows array
105	        const current = form.values.byPlayerId[row.playerId] ?? baseline;
106	
107	        return (
108	            baseline.response !== current.response ||
109	            baseline.goalie !== current.goalie ||
110	            baseline.comment !== current.comment
111	        );
112	    };
113	
114	    const grouped = useMemo(() => {
115	        const filteredRows = responses.filter((row) => {
116	            const searchTerm = filter.toLowerCase();
117	            // v8 ignore next -- optional chaining on name is a type-safety guard
118	            return (row.player.name?.toLowerCase().includes(searchTerm));
119	        });
120	
121	        return {
122	            yes: filteredRows.filter((r) => r.response === ResponseOption.Yes),
123	            no: filteredRows.filter((r) => r.response === ResponseOption.No),
124	            dunno: filteredRows.filter((r) => r.response === ResponseOption.Dunno),
125	            excused: filteredRows.filter((r) => r.response === ResponseOption.Excused),
126	            flaked: filteredRows.filter((r) => r.response === ResponseOption.Flaked),
127	            injured: filteredRows.filter((r) => r.response === ResponseOption.Injured),
128	            none: filteredRows.filter((r) => r.response == null),
129	        };
130	    }, [responses, filter]);
131	
132	    const handleSubmit = async (row: OutcomePlayerType) => {
133	        // v8 ignore next -- form is always initialised from the same rows array
134	        const responseValues = form.values.byPlayerId[row.playerId] ?? toResponseValues(row);
135	        if (!responseValues.response) return;
136	
137	        const notificationId = `response-${row.playerId}`;
138	        notifications.show({
139	            id: notificationId,
140	            loading: true,
141	            title: 'Updating response',
142	            message: 'Updating response...',
143	            autoClose: false,
144	            withCloseButton: false,
145	        });
146	
147	        setSavingId(row.playerId);
148	        try {
149	            await submitResponse({
150	                gameDayId: gameId,
151	                playerId: row.playerId,
152	                response: responseValues.response,
153	                goalie: !!responseValues.goalie,
154	                // v8 ignore next -- form normalises null to '' at init, so comment is always a string
155	                comment: responseValues.comment ?? null,
156	            });
157	            notifications.update({
158	                id: notificationId,
159	                color: 'teal',
160	                title: 'Response updated',
161	                message: 'Response updated successfully',
162	                icon: <IconCheck size={config.notificationIconSize} />,
163	                loading: false,
164	                autoClose: config.notificationAutoClose,
165	            });
166	        } catch (err) {
167	            const errorMessage = err instanceof Error ? err.message : 'Failed to update response';
168	            notifications.update({
169	                id: notificationId,
170	                color: 'red',
171	                title: 'Error',
172	                message: errorMessage,
173	                icon: <IconAlertTriangle size={config.notificationIconSize} />,
174	                loading: false,
175	                autoClose: false,
176	                withCloseButton: true,
177	            });
178	        } finally {
179	            setSavingId(null);
180	        }
181	    };
182	
183	    const renderGroup = (title: ResponseOption, items: OutcomePlayerType[]) => {
184	        if (items.length === 0) return null;
185	
186	        return (
187	            <Card key={title} withBorder shadow="xs" p="md" role="region" aria-label={title}>
188	                <CardSection h={6} bg={responseGroupBarColor[title]} />
189	                <Group justify="space-between" mb="lg" mt="md">
190	                    <Title order={2}>{title}: {items.length}</Title>
191	                </Group>
192	                <Stack gap="sm">
193	                    {items.map((row) => {
194	                        // v8 ignore next -- form is always initialised from the same rows array
195	                        const responseValues = form.values.byPlayerId[row.playerId] ?? toResponseValues(row);
196	                        // v8 ignore next -- null names are excluded by the search filter before rows are rendered
197	                        const ariaLabel = row.player.name ?? `Player ${row.playerId}`;
198	                        return (
199	                            <Flex
200	                                key={row.playerId}
201	                                role="group"
202	                                aria-label={ariaLabel}
203	                                data-player-id={row.playerId}
204	                                align="center"
205	                                gap="sm"
206	                                wrap="nowrap"
207	                            >
208	                                <Text fw={600} w={180}>
209	                                    {row.player.name}
210	                                </Text>
211	                                <Select
212	                                    aria-label="Response"
213	                                    data={Object.values(PlayerResponse).map((option) => ({
214	                                        value: option,
215	                                        label: option,
216	                                    }))}
217	                                    value={responseValues.response ?? ResponseOption.None}
218	                                    onChange={(value) => {
219	                                        const nextValue = value;
220	                                        form.setFieldValue(
221	                                            `byPlayerId.${row.playerId}.response`,
222	                                            // v8 ignore next -- 'None' never appears in the Select data array
223	                                            nextValue === ResponseOption.None ? null : nextValue,
224	                                        );
225	                                    }}
226	                                    size="sm"
227	                                    w={160}
228	                                />
229	                                <Checkbox
230	                                    label="Goalie"
231	                                    size="sm"
232	                                    {...form.getInputProps(
233	                                        `byPlayerId.${row.playerId}.goalie`,
234	                                        { type: 'checkbox' },
235	                                    )}
236	                                />
237	                                <TextInput
238	                                    placeholder="Comment"
239	                                    maxLength={127}
240	                                    {...form.getInputProps(`byPlayerId.${row.playerId}.comment`)}
241	                                    size="sm"
242	                                    style={{ flex: 1, minWidth: 220 }}
243	                                />
244	                                <Button
245	                                    variant="filled"
246	                                    size="sm"
247	                                    disabled={!isRowDirty(row)}
248	                                    loading={savingId === row.playerId}
249	                                    onClick={() => handleSubmit(row)}
250	                                >
251	                                    Update
252	                                </Button>
253	                            </Flex>
254	
255	                        );
256	                    })}
257	                </Stack>
258	            </Card>
259	        );
260	    };
261	
262	    return (
263	        <Stack gap="md">
264	            <Stack align="left" gap="xs">
265	                <Title order={2}>Responses</Title>
266	                <Text c="dimmed">Game {gameId}: {gameDate}</Text>
267	                <TextInput
268	                    placeholder="Search players"
269	                    value={filter}
270	                    onChange={(event) => setFilter(event.currentTarget.value)}
271	                />
272	            </Stack>
273	            {Object.values(ResponseOption).map((option) => (
274	                renderGroup(
275	                    option,
276	                    grouped[option.toLowerCase() as keyof typeof grouped],
277	                )
278	            ))}
279	        </Stack>
280	    );
281	};
